+<div class="settings-section">
+    <h4>Notifications</h4>
+    <p class="text-muted">Control how you receive notifications</p>
+    <hr />
+
+    <div class="mb-4">
+        <h6>Notification Channels</h6>
+        <div class="form-check form-switch mb-2">
+            <input class="form-check-input" type="checkbox" id="emailNotif"
+                   checked="@_emailNotifications"
+                   @onchange="e => _emailNotifications = (bool)e.Value!" />
+            <label class="form-check-label" for="emailNotif">Email Notifications</label>
+        </div>
+        <div class="form-check form-switch mb-2">
+            <input class="form-check-input" type="checkbox" id="pushNotif"
+                   checked="@_pushNotifications"
+                   @onchange="e => _pushNotifications = (bool)e.Value!" />
+            <label class="form-check-label" for="pushNotif">Push Notifications</label>
+        </div>
+        <div class="form-check form-switch mb-2">
+            <input class="form-check-input" type="checkbox" id="weeklyDigest"
+                   checked="@_weeklyDigest"
+                   @onchange="e => _weeklyDigest = (bool)e.Value!" />
+            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
+        </div>
+    </div>
+
+    <div class="mb-4">
+        <h6>Muted Channels</h6>
+        <p class="text-muted small">Uncheck a channel to unmute it</p>
+        @foreach (var channel in _allChannels)
+        {
+            <div class="form-check mb-1">
+                <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
+                       checked="@_mutedChannels.Contains(channel)"
+                       @onchange="e => ToggleMute(channel, (bool)e.Value!)" />
+                <label class="form-check-label" for="@($"ch-{channel}")">
+                    #@channel
+                </label>
+            </div>
+        }
+    </div>
+
+    @if (_statusMessage is not null)
+    {
+        <div class="alert alert-success alert-dismissible fade show" role="alert">
+            @_statusMessage
+            <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
+        </div>
+    }
+
+    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
+        @if (_saving)
+        {
+            <span class="spinner-border spinner-border-sm me-1"></span>
+        }
+        Save Preferences
+    </button>
+</div>
+
+@code {
+    [Parameter, EditorRequired] public NotificationPrefs Prefs { get; set; } = default!;
+    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }
+
+    private bool _emailNotifications;
+    private bool _pushNotifications;
+    private bool _weeklyDigest;
+    private HashSet<string> _mutedChannels = new();
+    private List<string> _allChannels = new();
+    private bool _saving;
+    private string? _statusMessage;
+
+    protected override void OnParametersSet()
+    {
+        if (!_saving)
+        {
+            _emailNotifications = Prefs.EmailNotifications;
+            _pushNotifications = Prefs.PushNotifications;
+            _weeklyDigest = Prefs.WeeklyDigest;
+            _mutedChannels = new HashSet<string>(Prefs.MutedChannels);
+            _allChannels = new List<string>(Prefs.MutedChannels);
+        }
+    }
+
+    private void ToggleMute(string channel, bool isMuted)
+    {
+        if (isMuted)
+            _mutedChannels.Add(channel);
+        else
+            _mutedChannels.Remove(channel);
+    }
+
+    private async Task SaveAsync()
+    {
+        _saving = true;
+        var updated = new NotificationPrefs(
+            _emailNotifications,
+            _pushNotifications,
+            _weeklyDigest,
+            _mutedChannels.ToList());
+        await OnSave.InvokeAsync(updated);
+        _saving = false;
+        _statusMessage = "Notification preferences saved!";
+    }
+}
+

