@using sv_84435ad585964901b757defd85549ae2.Models

<div class="settings-section">
    <h4>Appearance</h4>
    <p class="text-muted">Customize how the app looks and feels</p>
    <hr />

    <div class="row">
        <div class="col-md-7">
            @* Theme *@
            <div class="mb-4">
                <h6>Theme</h6>
                @foreach (var theme in new[] { "Light", "Dark", "System" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme"
                               id="@($"theme-{theme}")"
                               checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                    </div>
                }
            </div>

            @* Font Size *@
            <div class="mb-4">
                <h6>Font Size</h6>
                @foreach (var size in new[] { "Small", "Medium", "Large" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize"
                               id="@($"fs-{size}")"
                               checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                    </div>
                }
            </div>

            @* Language *@
            <div class="mb-4">
                <h6>Language</h6>
                <select class="form-select" style="max-width: 250px;"
                        @bind="_language">
                    <option value="English">English</option>
                    <option value="Spanish">Spanish</option>
                    <option value="French">French</option>
                    <option value="German">German</option>
                    <option value="Japanese">Japanese</option>
                    <option value="Portuguese">Portuguese</option>
                </select>
            </div>

            @* Compact Mode *@
            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode"
                           checked="@_compactMode"
                           @onchange="e => _compactMode = (bool)e.Value!" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>

            @if (_statusMessage is not null)
            {
                <div class="alert alert-success alert-dismissible fade show" role="alert">
                    @_statusMessage
                    <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
                </div>
            }

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>
        </div>

        @* Live Preview *@
        <div class="col-md-5">
            <AppearancePreview Theme="@_theme" FontSize="@_fontSize"
                               Language="@_language" CompactMode="@_compactMode" />
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public AppearanceSettings Settings { get; set; } = default!;
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _saving;
    private string? _statusMessage;

    protected override void OnParametersSet()
    {
        if (!_saving)
        {
            _theme = Settings.Theme;
            _fontSize = Settings.FontSize;
            _language = Settings.Language;
            _compactMode = Settings.CompactMode;
        }
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await OnSave.InvokeAsync(updated);
        _saving = false;
        _statusMessage = "Appearance settings saved!";
    }
}

