toolArgs.file_text:
/* ===== Settings Dashboard Layout ===== */
.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 120px);
    gap: 0;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
}

/* ===== Sidebar ===== */
.settings-sidebar {
    width: 220px;
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.25rem 0;
}

.sidebar-title {
    padding: 0 1.25rem 0.75rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.settings-sidebar .nav-link {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.6rem 1.25rem;
    color: #495057;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    border-left: 3px solid transparent;
    transition: all 0.15s ease;
}

.settings-sidebar .nav-link:hover {
    background: #e9ecef;
    color: #212529;
}

.settings-sidebar .nav-link.active {
    background: #e7f1ff;
    color: #0d6efd;
    font-weight: 600;
    border-left-color: #0d6efd;
}

.section-icon {
    font-size: 1.1rem;
}

/* ===== Content Area ===== */
.settings-content {
    flex: 1;
    padding: 2rem;
    overflow-y: auto;
}

.settings-section h4 {
    margin-bottom: 0.25rem;
}

/* ===== Avatar Preview ===== */
.avatar-preview {
    padding: 1rem;
    background: #f8f9fa;
    border-radius: 0.5rem;
    border: 1px solid #dee2e6;
}

.avatar-preview img {
    object-fit: cover;
    border: 3px solid #dee2e6;
}

/* ===== Appearance Preview ===== */
.appearance-preview {
    position: sticky;
    top: 1rem;
}

.preview-body {
    transition: all 0.2s ease;
    border-radius: 0.25rem;
    min-height: 180px;
}

.preview-light {
    background: #ffffff;
    color: #212529;
    border: 1px solid #dee2e6;
}

.preview-dark {
    background: #1e1e2e;
    color: #e0e0e0;
    border: 1px solid #444;
}

.preview-dark .text-muted {
    color: #a0a0b0 !important;
}

.preview-dark .badge.bg-secondary {
    background-color: #555 !important;
}

.preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
    color: #212529;
    border: 1px solid #dee2e6;
}

/* ===== Modal Overrides ===== */
.modal-backdrop {
    z-index: 1040;
}

.modal {
    z-index: 1050;
}

